class ERC20Token:
 def __init__(self, total_tokens):
 self.total_tokens = total_tokens
 self.balances = {}
 self.allowances = {}

 def total_supply(self):
 return self.total_tokens

 def balance_of(self, address):
 return self.balances.get(address, 0)

 def transfer(self, address, amount):
 if self.balances.get(address, 0) >= amount:
 self.balances[address] -= amount
 self.balances[self.address] += amount
 return True
 else:
 return False

 def approve(self, spender, amount):
 self.allowances[self.address] = {spender: amount}
 return True

 def transfer_from(self, from_address, to_address, amount):
 if self.allowances.get(from_address, {}).get(self.address, 0) >= amount and self.balances.get(from_address, 0) >= amount:
 self.balances[from_address] -= amount
 self.balances[to_address] += amount
 self.allowances[from_address][self.address] -= amount
 return True
 else:
 return False

public class ERC20Token {
 private int totalTokens;
 private Map<String, Integer> balances;
 private Map<String, Map<String, Integer>> allowances;

 public ERC20Token(int totalTokens) {
 this.totalTokens = totalTokens;
 this.balances = new HashMap<>();
 this.allowances = new HashMap<>();
 }

 public int totalSupply() {
 return totalTokens;
 }

 public int balanceOf(String address) {
 return balances.getOrDefault(address, 0);
 }

 public boolean transfer(String address, int amount) {
 if (balances.getOrDefault(address, 0) >= amount) {
 balances.put(address, balances.get(address) - amount);
 balances.put(this.address, balances.get(this.address) + amount);
 return true;
 } else {
 return false;
 }
 }

 public boolean approve(String spender, int amount) {
 allowances.put(this.address, Map.of(spender, amount));
 return true;
 }

 public boolean transferFrom(String fromAddress, String toAddress, int amount) {
 if (allowances.getOrDefault(fromAddress, Map.of()).getOrDefault(this.address, 0) >= amount && balances.getOrDefault(fromAddress, 0) >= amount) {
 balances.put(fromAddress, balances.get(fromAddress) - amount);
 balances.put(toAddress, balances.get(toAddress) + amount);
 allowances.get(fromAddress).put(this.address, allowances.get(fromAddress).get(this.address) - amount);
 return true;
 } else {
 return false;
 }
 }
}
